class ClassName:
    """文档字符串描述该类的作用"""
    class_variable = "共享值"

    def __init__(self, param1, param2):
        self.instance_attr1 = param1
        self.instance_attr2 = param2

    def method1(self):
        return f"{self.instance_attr1} 和 {self.instance_attr2}"

    @classmethod
    def class_method(cls):
        return cls.class_variable

    @staticmethod
    def static_method():
        return "静态方法"
